use std::collections::BTreeSet;use std::io::{self,Read};fn snap(s:&BTreeSet<i32>)->String{let mut parts=Vec::new();let(mut open,mut st,mut prev)=(false,0,0);for &v in s{if !open{st=v;prev=v;open=true}else if v==prev+1{prev=v}else{parts.push(format!("[{},{}]",st,prev));st=v;prev=v;}}if open{parts.push(format!("[{},{}]",st,prev));}format!("[{}]",parts.join(","))}fn main(){let mut x=String::new();io::stdin().read_to_string(&mut x).unwrap();let d:Vec<&str>=x.split_whitespace().collect();if d.is_empty(){return};let mut idx=0;let t:usize=d[idx].parse().unwrap();idx+=1;let mut cases=Vec::new();for _ in 0..t{let ops:usize=d[idx].parse().unwrap();idx+=1;let mut seen=BTreeSet::new();let mut snaps=Vec::new();for _ in 0..ops{let op=d[idx];idx+=1;if op=="A"{seen.insert(d[idx].parse().unwrap());idx+=1}else{snaps.push(snap(&seen));}}cases.push(format!("[{}]",snaps.join(",")));}print!("{}",cases.join("\n\n"));}
